var body = $json.body || $json;
var findings = body.findings || [];
var legalValidation = body.legalValidation || {};
var requirements = body.requirements || {};
var proposalAnalysis = body.proposalAnalysis || {};
var procurementInfo = body.procurementInfo || {};

var procStr = JSON.stringify(procurementInfo, null, 2).substring(0, 3000);
var reqStr = JSON.stringify(requirements, null, 2).substring(0, 20000);
var findingsStr = JSON.stringify(findings, null, 2).substring(0, 30000);
var legalStr = JSON.stringify(legalValidation, null, 2).substring(0, 20000);
var proposalStr = JSON.stringify(proposalAnalysis, null, 2).substring(0, 15000);

// Count stats
var compliant = 0, partial = 0, nonCompliant = 0, missing = 0;
for (var i = 0; i < findings.length; i++) {
  var s = findings[i].status;
  if (s === 'COMPLIANT') compliant++;
  else if (s === 'PARTIALLY_COMPLIANT') partial++;
  else if (s === 'NON_COMPLIANT') nonCompliant++;
  else if (s === 'MISSING') missing++;
}

var overallRec = (legalValidation.overall_conclusion || {}).action || 'НЕПОСОЧЕНО';

var p = 'Ти си секретар на оценителна комисия по обществена поръчка. Изготвяш ПРОТОКОЛ С МОТИВИ ЗА ОТСТРАНЯВАНЕ по модела на реални протоколи от българската практика.

';
p += '## ДАННИ ЗА ПОРЪЧКАТА:
' + procStr + '

';
p += '## СТАТИСТИКА:
';
p += '- Общо проверени технически изисквания: ' + findings.length + '
';
p += '- Съответстващи: ' + compliant + '
';
p += '- Частично съответстващи: ' + partial + '
';
p += '- Несъответстващи: ' + nonCompliant + '
';
p += '- Липсващи: ' + missing + '
';
p += '- Обща препоръка: ' + overallRec + '

';
p += '## ИЗВЛЕЧЕНИ ИЗИСКВАНИЯ:
' + reqStr + '

';
p += '## АНАЛИЗ НА ПРЕДЛОЖЕНИЕТО (вътрешни противоречия, липси, агрегирани данни):
' + proposalStr + '

';
p += '## КОНСТАТАЦИИ ПО ВСЯКО ИЗИСКВАНЕ:
' + findingsStr + '

';
p += '## ПРАВНИ МОТИВИ:
' + legalStr + '

';
p += '## СТРУКТУРА НА ПРОТОКОЛА — СЛЕДВАЙ ТАЗИ ТОЧНА СТРУКТУРА:

';
p += '# МОТИВИ
';
p += '## за несъответствие на техническото предложение с изискванията на документацията

';
p += '**Обществена поръчка**: [предмет от данните]
';
p += '**Възложител**: [от данните]
';
p += '**Участник**: [от данните или "Участникът"]

';
p += '---

';
p += 'Започни с ВЪВЕЖДАЩ ПАРАГРАФ в следния стил:
';
p += '"Техническо предложение: Офертата на участника в частта на техническото предложение, представен в Плик № 2 (или аналогично), съдържа [кратко описание на структурата]. При проверката на техническото предложение на участника за съответствие с изискванията на документацията, комисията констатира следните несъответствия:"

';
p += '---

';
p += '## ОСНОВНА ЧАСТ — ТОЧКА ПО ТОЧКА

';
p += 'За ВСЯКО изискване, което има статус PARTIALLY_COMPLIANT, NON_COMPLIANT или MISSING, изготви ОТДЕЛНА ТОЧКА в следната структура:

';
p += '### Точка [N]: [Заглавие на изискването]

';
p += '**Изискване на възложителя:**
';
p += '"Съгласно [секция] от документацията за участие, участникът е длъжен да представи [ДОСЛОВЕН цитат на изискването]."

';
p += '**Очаквано съдържание:**
';
p += 'Описание на КОНКРЕТНИТЕ елементи, които ТП трябва да съдържа за покриване на изискването — включително всичките подточки.

';
p += '**Представено от участника:**
';
p += 'Описание на КАКВО РЕАЛНО е представил участникът — с ДОСЛОВНИ ЦИТАТИ и позовавания на секции/страници.

';
p += '**Констатирани несъответствия:**

';
p += 'За ВСЯКО несъответствие — КОНКРЕТЕН параграф в следния стил:

';
p += '1. **Противоречия между части на предложението:**
';
p += '"В работната програма (стр. X) за дейност [име] участникът е посочил [Y] работника, докато в линейния график (стр. Z) за същата дейност са предвидени [W] работника. Налице е несъответствие между двете части на техническото предложение."

';
p += '2. **Липсващи елементи:**
';
p += '"Изискването предвижда описание на [X] за всяка позиция от КСС. Участникът е описал [X] за позиции [списък], без да адресира позиции [списък]. Не е представено описание за [N] от общо [M] позиции."

';
p += '3. **Агрегирани данни:**
';
p += '"В линейния график позиции [X-Y] от КСС са обединени в една обща дейност "[Име]" без индивидуална разбивка. Документацията изисква всяка позиция да бъде представена поотделно."

';
p += '4. **Липса на конкретика:**
';
p += '"Не е представено разпределение на отговорностите по видове строителни дейности. Участникът е представил обща организационна структура без конкретна връзка с дейностите по КСС."

';
p += '**Извод по точка [N]:**
';
p += '"Посочените обстоятелства обосновават извод за несъответствие на техническото предложение с изискването на [секция] от документацията."

';
p += '---

';
p += '## ОБОБЩЕНИ МОТИВИ ЗА ОТСТРАНЯВАНЕ

';
p += 'След индивидуалните точки — ОБОБЩЕН ИЗВОД:

';
p += '"На основание гореизложеното, комисията констатира, че техническото предложение на участника съдържа следните несъответствия с изискванията на документацията:
';
p += '1. [Кратко описание на несъответствие 1]
';
p += '2. [Кратко описание на несъответствие 2]
';
p += '...

';
p += 'Посочените обстоятелства в тяхната съвкупност обосновават извод, че офертата на участника не отговаря на предварително обявените условия на поръчката, което представлява основание за отстраняване по чл. 107, т. 2, буква 'а' от ЗОП."

';
p += '---

';
p += '*Забележка: Настоящите мотиви са подготвени с помощта на AI анализ и подлежат на потвърждение от оценителната комисия.*

';
p += '## КРИТИЧНИ ПРАВИЛА:
';
p += '- Протоколът ТРЯБВА да е обемен — 5-15 страници (3000-7000 думи)
';
p += '- Всяка точка трябва да има ДОСЛОВНИ ЦИТАТИ от документацията И от предложението
';
p += '- Всяко несъответствие — с КОНКРЕТНИ числа, позиции, страници
';
p += '- Структурата е ТОЧКА ПО ТОЧКА, не по теми
';
p += '- НЕ споменавай ЕЕДОП, ценово предложение, критерии за подбор
';
p += '- Правен извод за ВСЯКА точка + ОБОБЩЕН извод в края
';
p += '- Пиши на формален правен български език
';
p += '- НЕ добавяй констатации извън предоставените данни
';
p += '- За COMPLIANT изисквания — НЕ ги включвай в мотивите (само несъответствията)
';
p += '- Ако Обща препоръка е ACCEPT — протоколът трябва да отразява липсата на съществени нарушения';

return [{ json: { prompt: p } }];

var raw = ($json.text || $json.response || '').trim();

// If the response is wrapped in json/markdown blocks, extract
var reportText = raw;
var m = raw.match(/```(?:markdown)?\s*([\s\S]*?)```/);
if (m) reportText = m[1].trim();

// Basic cleanup
if (!reportText || reportText.length < 100) {
  reportText = '# ПРОТОКОЛ\n\nГрешка при генериране на протокола. Моля, прегледайте данните ръчно.\n';
}

return [{ json: { reportText: reportText } }];
